UPDATE outbox_messages
SET status = 'PUBLISHING', lock_owner = #{owner}, lock_until = #{lockedUntil}
WHERE id = #{id}
  AND (status = 'PENDING' OR (status = 'PUBLISHING' AND lock_until < UTC_TIMESTAMP()))

UPDATE outbox_messages
SET status = #{status}, lock_owner = NULL, lock_until = NULL
WHERE id = #{id} AND status = 'PUBLISHING' AND lock_owner = #{owner}

UPDATE outbox_messages
SET status = 'PENDING', lock_owner = NULL, lock_until = NULL
WHERE id = #{id} AND status = 'PUBLISHING' AND lock_owner = #{owner}
